    private String requiredAttribute(Element element, String attributeName, String errorMessage) {
        String value = element.getAttribute(attributeName);
        if (value == null || value.trim().isEmpty()) {
            throw new SamlProcessingException(errorMessage);
        }
        return value.trim();
    }

    private Instant parseInstant(String value, String errorMessage) {
        try {
            return Instant.parse(value);
        } catch (Exception e) {
            throw new SamlProcessingException(errorMessage + ": " + value, e);
        }
    }

    private String textContent(Element element) {
        String text = element.getTextContent();
        return text == null ? null : text.trim();
    }
