class SessionManager {

    public AuthenticatedSession createSession(SamlResponse samlResponse) {
        if (samlResponse == null) {
            throw new SamlProcessingException("SAML response must not be null");
        }
        if (samlResponse.getAssertions() == null || samlResponse.getAssertions().isEmpty()) {
            throw new SamlProcessingException("SAML response does not contain assertions");
        }

        SamlAssertion selectedAssertion = selectUsableAssertion(samlResponse.getAssertions());
        validateAssertionTimeWindow(selectedAssertion);

        AuthenticatedSession session = new AuthenticatedSession();
        session.setSessionId(UUID.randomUUID().toString());
        session.setPrincipal(selectedAssertion.getSubject());
        session.setCreatedAt(Instant.now());
        session.setExpiresAt(resolveExpiration(selectedAssertion));
        session.setAttributes(flattenAttributes(selectedAssertion.getAttributes()));
        session.setSourceResponseId(samlResponse.getId());
        session.setSourceAssertionId(selectedAssertion.getId());

        return session;
    }

    private SamlAssertion selectUsableAssertion(List<SamlAssertion> assertions) {
        for (SamlAssertion assertion : assertions) {
            if (assertion.getSubject() != null && !assertion.getSubject().trim().isEmpty()) {
                return assertion;
            }
        }
        throw new SamlProcessingException("No usable assertion found for session creation");
    }

    private void validateAssertionTimeWindow(SamlAssertion assertion) {
        Instant now = Instant.now();

        if (assertion.getNotBefore() != null && now.isBefore(assertion.getNotBefore())) {
            throw new SamlProcessingException("Assertion is not yet valid");
        }

        if (assertion.getNotOnOrAfter() != null && !now.isBefore(assertion.getNotOnOrAfter())) {
            throw new SamlProcessingException("Assertion has expired");
        }
    }

    private Instant resolveExpiration(SamlAssertion assertion) {
        if (assertion.getNotOnOrAfter() != null) {
            return assertion.getNotOnOrAfter();
        }
        return Instant.now().plusSeconds(3600);
    }

    private Map<String, String> flattenAttributes(Map<String, List<String>> attributes) {
        if (attributes == null || attributes.isEmpty()) {
            return Collections.emptyMap();
        }

        Map<String, String> flattened = new LinkedHashMap<>();
        for (Map.Entry<String, List<String>> entry : attributes.entrySet()) {
            List<String> values = entry.getValue();
            if (values == null || values.isEmpty()) {
                flattened.put(entry.getKey(), "");
            } else if (values.size() == 1) {
                flattened.put(entry.getKey(), values.get(0));
            } else {
                flattened.put(entry.getKey(), String.join(",", values));
            }
        }
        return flattened;
    }
}

